export default "v-scroll{--v-scroll-hit-width:14px;--v-scroll-width:15px;--v-scroll-radius:999px;--v-scroll-track-padding:2px;--v-scroll-min-bar:30px;--v-scroll-track-bg:#00000014;--v-scroll-track-outline:#0000001f;--v-scroll-bar-bg:#c7c7c7;--v-scroll-bar-bg-hover:#adadad;--v-scroll-bar-bg-dragging:#8f8f8f;--v-scroll-cursor:url(/scroll.svg) 10 10, ns-resize;--v-scroll-cursor-grab:url(/grab.svg) 7 7, grabbing;display:block;position:relative}v-scroll::part(viewport){scrollbar-width:none;height:100%;overflow:auto}v-scroll::part(viewport)::-webkit-scrollbar{display:none}v-scroll::part(rail){width:var(--v-scroll-hit-width);opacity:0;cursor:var(--v-scroll-cursor);transition:opacity .35s linear;position:absolute;inset:0 0 0 auto}v-scroll::part(track){background:0 0;width:6px;padding:0;transition:width .22s,padding .22s,background .22s,box-shadow .22s;position:absolute;inset:0 0 0 auto;box-shadow:inset 0 0 0 1px #0000}v-scroll::part(thumb){width:35%;display:var(--thumb_display,block);height:var(--thumb_height,var(--v-scroll-min-bar));min-height:var(--v-scroll-min-bar);border-radius:var(--v-scroll-radius);background:var(--v-scroll-bar-bg);cursor:inherit;transform:translateX(-50%) translateY(var(--thumb_y,0px));transition:background .2s,left .22s,right .22s;position:absolute;top:0;left:50%;right:0}v-scroll[scrollable][active]::part(rail),v-scroll[dragging]::part(rail){opacity:1}v-scroll[scrollable][active]::part(track),v-scroll[dragging]::part(track){width:var(--v-scroll-width);padding:0 var(--v-scroll-track-padding);background:var(--v-scroll-track-bg);box-shadow:inset 0 0 0 1px var(--v-scroll-track-outline)}v-scroll[scrollable][active]::part(thumb){background:var(--v-scroll-bar-bg-hover)}v-scroll[dragging]::part(rail),v-scroll[dragging]::part(thumb){cursor:var(--v-scroll-cursor-grab)}v-scroll[dragging]::part(thumb){background:var(--v-scroll-bar-bg-dragging)}";
